const fs = require('fs');
const zlib = require('zlib');

function makePng(pixels) {
  function chunk(name, data) {
    const nameB = Buffer.from(name);
    const c = Buffer.concat([nameB, data]);
    const crc = crc32(c);
    const len = Buffer.allocUnsafe(4); len.writeUInt32BE(data.length);
    const crcB = Buffer.allocUnsafe(4); crcB.writeUInt32BE(crc >>> 0);
    return Buffer.concat([len, c, crcB]);
  }
  function crc32(buf) {
    let crc = 0xFFFFFFFF;
    const table = makeCrcTable();
    for (const b of buf) crc = (crc >>> 8) ^ table[(crc ^ b) & 0xFF];
    return (crc ^ 0xFFFFFFFF) >>> 0;
  }
  let table;
  function makeCrcTable() {
    if (table) return table;
    table = new Uint32Array(256);
    for (let i = 0; i < 256; i++) {
      let c = i;
      for (let j = 0; j < 8; j++) c = (c & 1) ? (0xEDB88320 ^ (c >>> 1)) : (c >>> 1);
      table[i] = c;
    }
    return table;
  }

  const sig = Buffer.from([137,80,78,71,13,10,26,10]);
  const ihdr = Buffer.allocUnsafe(13);
  ihdr.writeUInt32BE(16, 0); ihdr.writeUInt32BE(16, 4);
  ihdr[8]=8; ihdr[9]=6; ihdr[10]=0; ihdr[11]=0; ihdr[12]=0;

  const rawParts = [];
  for (const row of pixels) {
    rawParts.push(Buffer.from([0]));
    for (const px of row) rawParts.push(Buffer.from(px));
  }
  const raw = Buffer.concat(rawParts);
  const compressed = zlib.deflateSync(raw);

  return Buffer.concat([sig, chunk('IHDR', ihdr), chunk('IDAT', compressed), chunk('IEND', Buffer.alloc(0))]);
}

