package com.strayneko.rubysword.item;

import com.strayneko.rubysword.Rubysword;
import net.minecraft.item.Item;
import net.minecraft.item.ToolMaterial;
import net.minecraft.registry.Registries;
import net.minecraft.registry.Registry;
import net.minecraft.registry.RegistryKeys;
import net.minecraft.registry.tag.BlockTags;
import net.minecraft.registry.tag.TagKey;
import net.minecraft.util.Identifier;

public class ModItems {

    public static final ToolMaterial RUBY_MATERIAL = new ToolMaterial(
        BlockTags.INCORRECT_FOR_DIAMOND_TOOL,
        2031,   // durability (same as diamond: 1561, ruby is tougher)
        8.0F,   // mining speed
        3.0F,   // attack damage bonus
        14,     // enchantability (better than diamond's 10)
        TagKey.of(RegistryKeys.ITEM, Identifier.of(Rubysword.MOD_ID, "repairs_ruby_tools"))
    );

    public static final Item RUBY = register("ruby",
        new Item(new Item.Settings()));

    public static final Item RUBY_SWORD = register("ruby_sword",
        new Item(new Item.Settings().sword(RUBY_MATERIAL, 3.0F, -2.4F)));

    private static Item register(String name, Item item) {
        return Registry.register(Registries.ITEM, Identifier.of(Rubysword.MOD_ID, name), item);
    }

    public static void initialize() {
        Rubysword.LOGGER.info("Registering mod items for " + Rubysword.MOD_ID);
    }
}

